import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { CentsPipe } from '../../shared/cents.pipe';
import { User } from '../../core/models';

interface TenantRow {
  user: User;
  unitNumber: string;
  rentCents: number;
  delinquent: boolean;
}

@Component({
  selector: 'app-tenants-list',
  standalone: true,
  imports: [CommonModule, RouterLink, CentsPipe],
  templateUrl: './tenants-list.component.html',
  styleUrl: './tenants-list.component.css',
})
export class TenantsListComponent {
  readonly loading = signal(false);
  readonly error = signal('');

  /** Tenant users only. */
  readonly tenants = signal<User[]>([
    { id: 't1', name: 'Alex Rivera', email: 'tenant1@demo', role: 'tenant' },
    { id: 't2', name: 'Bailey Chen', email: 'tenant2@demo', role: 'tenant' },
    { id: 't3', name: 'Casey Morgan', email: 'tenant3@demo', role: 'tenant' },
  ]);

  /** Unit + rent + delinquency lookup by tenant id. */
  private readonly meta: Record<string, { unit: string; rentCents: number; delinquent: boolean }> = {
    t1: { unit: '101', rentCents: 120000, delinquent: false },
    t2: { unit: '102', rentCents: 180000, delinquent: false },
    t3: { unit: '201', rentCents: 190000, delinquent: true },
  };

  rowFor(user: User): TenantRow {
    const m = this.meta[user.id] ?? { unit: '—', rentCents: 0, delinquent: false };
    return { user, unitNumber: m.unit, rentCents: m.rentCents, delinquent: m.delinquent };
  }
}
